mapper.select:
select b.id, b.booking_no, b.venue_id, v.name as venue_name, v.location as venue_location, b.booking_date, b.start_time, b.end_time, b.person_count, b.status, b.remark, b.create_time from booking b left join venue v on b.venue_id = v.id where b.user_id = #{userId}
and b.status = #{status}
order by b.id desc
